#include <bits/stdc++.h>using namespace std; int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);     int t;    cin >> t;     while (t--) {        int n;        string s;        cin >> n >> s;         vector<bool> visited(n, false);        int current = 0;         visited[current] = true;         for (int i = 0; i < n; i++) {            if (s[current] == 'R')                current++;            else                current--;             visited[current] = true;        }         int count = 0;        for (bool v : visited)            if (v) count++;         cout << count << "\n";    }     return 0;}